const root = $json ?? {};
const body = (root.body && typeof root.body === 'object') ? root.body : {};
const nested = (body.body && typeof body.body === 'object') ? body.body : {};
const input = nested && Object.keys(nested).length ? nested : body;
const payload = input.payload ?? input;
const requestedAction = String(root.action ?? body.action ?? nested.action ?? payload.action ?? root.query?.action ?? 'ping').toLowerCase().trim();
const task = root.task ?? body.task ?? nested.task ?? payload.task ?? root.text ?? body.text ?? nested.text ?? payload.text ?? '';
const runId = root.run_id ?? body.run_id ?? nested.run_id ?? payload.run_id ?? root.runId ?? body.runId ?? nested.runId ?? payload.runId ?? `run_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;

const jiraIssueKey = String(root.jira_issue_key ?? body.jira_issue_key ?? nested.jira_issue_key ?? payload.jira_issue_key ?? root.issue_key ?? body.issue_key ?? nested.issue_key ?? payload.issue_key ?? '').trim();
const jiraBaseUrl = String(root.jira_base_url ?? body.jira_base_url ?? nested.jira_base_url ?? payload.jira_base_url ?? root.jira?.base_url ?? body.jira?.base_url ?? '').trim();
const jiraEmail = String(root.jira_email ?? body.jira_email ?? nested.jira_email ?? payload.jira_email ?? root.jira?.email ?? body.jira?.email ?? '').trim();
const jiraApiToken = String(root.jira_api_token ?? body.jira_api_token ?? nested.jira_api_token ?? payload.jira_api_token ?? root.jira?.api_token ?? body.jira?.api_token ?? '').trim();

const headers = root.headers ?? body.headers ?? {};
const host = headers.host ?? headers.Host ?? '';
const protocol = headers['x-forwarded-proto'] ?? headers['X-Forwarded-Proto'] ?? 'https';

let resolvedAction = requestedAction;
let targetPath = 'mcp-ping';
let forwardBody = { action: 'ping', requestedAction, run_id: runId };

if (requestedAction === 'planner') {
  targetPath = 'planner-entry';
  forwardBody = { task: task || 'No task provided', run_id: runId };
} else if (requestedAction === 'full_pipeline') {
  targetPath = 'whatsapp-intake';
  forwardBody = {
    text: task || 'No task provided',
    run_id: runId,
    jira_issue_key: jiraIssueKey,
    jira_base_url: jiraBaseUrl,
    jira_email: jiraEmail,
    jira_api_token: jiraApiToken
  };
} else if (requestedAction === 'ping') {
  targetPath = 'mcp-ping';
  forwardBody = { action: 'ping', requestedAction, run_id: runId };
} else {
  resolvedAction = 'unsupported';
  targetPath = 'mcp-ping';
  forwardBody = { action: 'ping', requestedAction, run_id: runId };
}

const targetUrl = host ? `${protocol}://${host}/webhook/${targetPath}` : `https://invalid-host/webhook/${targetPath}`;

return [{
  json: {
    requestedAction,
    resolvedAction,
    run_id: runId,
    targetPath,
    targetUrl,
    forwardBody
  }
}];

return [{
  json: {
    status: 'ok',
    run_id: $json.run_id ?? $json.result?.run_id,
    result: $json,
    timestamp: new Date().toISOString()
  }
}];
